from typing import List

def solve(maze: List[List[int]]) -> bool:
    rows, cols = len(maze), len(maze[0])
    def backtrack(r, c, count_walls):
        # Base case: if we reach the end, it's valid
        if r == rows - 1 and c == cols - 1:
            return True

        # If we're at the end of a row, try to backtrack to the previous row
        if r > 0 and backtrack(r - 1, c, count_walls):
            return True
        # If we're at the end of a column, try to backtrack to the previous column
        if c > 0 and backtrack(r, c - 1, count_walls):
            return True

        # If we can't backtrack, try to place a wall at the current cell
        if count_walls < rows * cols // 2:
            maze[r][c] = 1
            if backtrack(r, c, count_walls + 1):
                return True
            maze[r][c] = 0
        # If we can't place a wall, backtrack
        return False
    return backtrack(0, 0, 0)

